     1→import { useRef, useEffect, type ReactNode } from "react";
     2→import { inView, animate } from "motion";
     3→
     4→interface FadeInSectionProps {
     5→  children: ReactNode;
     6→  direction?: "up" | "down" | "left" | "right";
     7→  delay?: number;
     8→  threshold?: number;
     9→  className?: string;
    10→}
    11→
    12→const directionMap = {
    13→  up: { y: [30, 0] },
    14→  down: { y: [-30, 0] },
    15→  left: { x: [30, 0] },
    16→  right: { x: [-30, 0] },
    17→};
    18→
    19→export default function FadeInSection({
    20→  children,
    21→  direction = "up",
    22→  delay = 0,
    23→  threshold = 0.2,
    24→  className = "",
    25→}: FadeInSectionProps) {
    26→  const ref = useRef<HTMLDivElement>(null);
    27→
    28→  useEffect(() => {
    29→    const element = ref.current;
    30→    if (!element) return;
    31→
    32→    // Check for reduced motion preference
    33→    const prefersReducedMotion = window.matchMedia(
    34→      "(prefers-reduced-motion: reduce)"
    35→    ).matches;
    36→
    37→    if (prefersReducedMotion) {
    38→      element.style.opacity = "1";
    39→      return;
    40→    }
    41→
    42→    // Set initial state
    43→    element.style.opacity = "0";
    44→
    45→    const cleanup = inView(
    46→      element,
    47→      () => {
    48→        animate(
    49→          element,
    50→          {
    51→            opacity: [0, 1],
    52→            ...directionMap[direction],
    53→          },
    54→          {
    55→            duration: 0.5,
    56→            easing: [0.4, 0, 0.2, 1],
    57→            delay,
    58→          }
    59→        );
    60→      },
    61→      { amount: threshold }
    62→    );
    63→
    64→    return cleanup;
    65→  }, [direction, delay, threshold]);
    66→
    67→  return (
    68→    <div ref={ref} className={className}>
    69→      {children}
    70→    </div>
    71→  );
    72→}
    73→

