     1→import { useRef, useEffect, useState } from "react";
     2→
     3→interface CountUpProps {
     4→  end: number;
     5→  duration?: number;
     6→  suffix?: string;
     7→  prefix?: string;
     8→  className?: string;
     9→}
    10→
    11→export default function CountUp({
    12→  end,
    13→  duration = 2000,
    14→  suffix = "",
    15→  prefix = "",
    16→  className = "",
    17→}: CountUpProps) {
    18→  const ref = useRef<HTMLSpanElement>(null);
    19→  const [hasAnimated, setHasAnimated] = useState(false);
    20→
    21→  useEffect(() => {
    22→    const element = ref.current;
    23→    if (!element || hasAnimated) return;
    24→
    25→    // Check for reduced motion preference
    26→    const prefersReducedMotion = window.matchMedia(
    27→      "(prefers-reduced-motion: reduce)"
    28→    ).matches;
    29→
    30→    if (prefersReducedMotion) {
    31→      element.textContent = `${prefix}${end}${suffix}`;
    32→      return;
    33→    }
    34→
    35→    // Use Intersection Observer to trigger animation when in view
    36→    const observer = new IntersectionObserver(
    37→      async (entries) => {
    38→        const [entry] = entries;
    39→        if (entry.isIntersecting && !hasAnimated) {
    40→          setHasAnimated(true);
    41→          observer.disconnect();
    42→
    43→          // Dynamically load GSAP
    44→          const { loadGSAP } = await import("../../lib/animations");
    45→          const { gsap } = await loadGSAP();
    46→
    47→          const counter = { value: 0 };
    48→          gsap.to(counter, {
    49→            value: end,
    50→            duration: duration / 1000,
    51→            ease: "power2.out",
    52→            onUpdate: () => {
    53→              if (element) {
    54→                element.textContent = `${prefix}${Math.round(counter.value)}${suffix}`;
    55→              }
    56→            },
    57→          });
    58→        }
    59→      },
    60→      { threshold: 0.5 }
    61→    );
    62→
    63→    observer.observe(element);
    64→
    65→    return () => observer.disconnect();
    66→  }, [end, duration, suffix, prefix, hasAnimated]);
    67→
    68→  return (
    69→    <span ref={ref} className={className}>
    70→      {prefix}0{suffix}
    71→    </span>
    72→  );
    73→}
    74→

